module ModifyCertificatesResult =
  struct
    type modifyCertificatesResult = {
      certificate: Certificate.t option }
    and responseMetaData = unit
    and t =
      {
      modifyCertificatesResult: modifyCertificatesResult ;
      responseMetaData: responseMetaData }
    type error =
      [ `CertificateNotFoundFault of CertificateNotFoundFault.t 
      | `Unknown_operation_error of (string * string option) ]
    let context_ = "ModifyCertificatesResult"
    let make ?certificate =
      fun () ->
        { modifyCertificatesResult = { certificate }; responseMetaData = () }
    let error_of_json name json =
      match name with
      | "CertificateNotFoundFault" ->
          `CertificateNotFoundFault (CertificateNotFoundFault.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "CertificateNotFoundFault" ->
          `CertificateNotFoundFault (CertificateNotFoundFault.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `CertificateNotFoundFault e ->
          `Assoc
            [("error", (`String "CertificateNotFoundFault"));
            ("details", (CertificateNotFoundFault.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value t =
      let x = t.modifyCertificatesResult in
      structure_to_wrapped_value
        [("Certificate", (Option.map x.certificate ~f:Certificate.to_value))]
        ~wrapper:"ModifyCertificatesResult" ~response:"ResponseMetaData"
    let to_query v = to_query to_value v
    let of_xml t =
      let xml_arg0 =
        Xml.child_exn ~context:context_ t "ModifyCertificatesResult" in
      let certificate =
        (Option.map ~f:Certificate.of_xml) (Xml.child xml_arg0 "Certificate") in
      make ?certificate ()
    let of_json json =
      let certificate = field_map json "Certificate" Certificate.of_json in
      make ?certificate ()
    let to_json v = composed_to_json to_value v
  end
